import random
from typing import List, Dict, Tuple

# Let's assume that we have two discount codes available at this point 
# (one is admin-only and one is for user with id "1234")
discount_codes = {
    'admin': {'type': 'percent', 'value': 50},   # 50% off for admins
    'user_id:1234': {'type': 'fixed', 'value': 10}  # $10 off for user with id "1234"
}

# This is a mock function. In real scenario, it would check permissions from DB or other secure places.
def validate_user(user: Dict) -> bool:
    return True if 'admin' in user['permissions'] else False

class CheckoutProcess:
    
    def __init__(self, cart: List[Dict], user: Dict):
        self.cart = cart
        self.user = user
        self.validated_cart = []  # after validate_items() called
        self.discounted_price = 0  # After apply_discounts() called
        self.total_tax = 0  # After calculate_tax() is called
        
    def validate_items(self) -> List[Dict]:
        for item in self.cart:
            if 'valid' not in item or item['valid'] == True:
                self.validated_cart.append(item)
        return self.validated_cart
    
    def apply_discounts(self, code: str = None):
        discount = 0
        if validate_user(self.user) and 'admin' in code:   # Admin-only discount code
            discount = (discount_codes['admin']['value'] / 100) * sum([i["price"] for i in self.validated_cart])
            
        elif f"user_id:{self.user['id']}" == code and 'user_id:1234' in discount_codes:   # Specific user tier discount code 
            discount = discount_codes[f"user_id:{self.user['id']}"]['value']
            
        self.discounted_price = sum([i["price"] for i in self.validated_cart]) - discount
    
    def calculate_tax(self, tax_rate=5.0):  # Assuming india has a standard rate of 5%
        self.total_tax = (tax_rate / 100) * self.discounted_price
        
    def process_payment(self, payment: Dict):
        if payment['amount'] >= self.discounted_price + self.total_tax:
            return True   # Payment successful
        else:
            return False  # Insufficient funds
    
    def create_order(self) -> Dict[str, any]:
        order = {
            'id': random.randint(100000, 999999),
            'user': self.user['name'],
            'total': round(self.discounted_price + self.total_tax, 2),
            'items': [i["name"] for i in self.validated_cart]
        }
        
        return order   # The final processed order record